3_real_world_example.code:
class BankAccount {
  // 1. You MUST declare the private field upfront
  #balance = 0;

  constructor(initialDeposit) {
    this.#balance = initialDeposit;
  }

  // 2. Methods inside the class can access it safely
  deposit(amount) {
    this.#balance += amount;
  }

  getBalance() {
    return this.#balance;
  }
}

const myAccount = new BankAccount(100);
myAccount.deposit(50);
console.log(myAccount.getBalance()); // 150

//  3. The outside world cannot touch it!
// console.log(myAccount.#balance); // SyntaxError!

